def determinant_4x4(matrix: list[list[int|float]]) -> float:
    def determinant_3x3(m: list[list[int|float]]) -> float:
        return (
            m[0][0] * (m[1][1] * m[2][2] - m[1][2] * m[2][1])
            - m[0][1] * (m[1][0] * m[2][2] - m[1][2] * m[2][0])
            + m[0][2] * (m[1][0] * m[2][1] - m[1][1] * m[2][0])
        )

    def get_minor(m: list[list[int|float]], row: int, col: int) -> list[list[int|float]]:
        return [
            [m[r][c] for c in range(len(m)) if c != col]
            for r in range(len(m)) if r != row
        ]

    det = 0.0
    for col in range(4):
        cofactor = ((-1) ** col) * matrix[0][col] * determinant_3x3(get_minor(matrix, 0, col))
        det += cofactor
    return det

